head.script:
scwin.onpageload = function() {

    var codeOptions = [
        { grpCd : "FM050", compID: "acb_clntKnd,gr_poorAcctRecv:clntKnd"},
        { grpCd : "FM051", compID : "gr_poorAcctRecv:useYn" }
    ];
    $c.data.setCommonCode(codeOptions);

    // scwin.f_Header();
	scwin.f_Reset();


}; 

